div.p:
Without restrict: Compiler assumes worst case (any overlap possible)
c
void copy(float* dst, float* src, size_t n) {
for (size_t i = 0; i < n; i++)
dst[i] = src[i];  // May NOT vectorize!
}

With restrict: Compiler trusts no aliasing
c
void copy(float* restrict dst,
const float* restrict src, size_t n) {
for (size_t i = 0; i < n; i++)
dst[i] = src[i];  // WILL vectorize!
}
